#!/usr/bin/env node
/* eslint-disable no-console -- CLI script: stdout is the user-facing surface. */
/**
 * Generates `.dev.vars` from the single source `.env`.
 *
 * Wrangler injects `.dev.vars` into the Worker `env` binding at dev time.
 * Vite/Astro reads `.env` at build time. The two readers do not share a
 * file format or load path, so this script bridges them: it filters the
 * runtime-only keys out of `.env` and writes them to `.dev.vars` with a
 * "do not edit" header. Direnv (`.envrc`) loads `.env` into the shell so
 * developers maintain a single source.
 *
 * Idempotent — only writes when the rendered output differs.
 *
 * Library exports (used by vitest):
 *   RUNTIME_KEYS, parseDotenv, selectRuntime, renderDevVars, syncDevVars
 */
import { existsSync, readFileSync, writeFileSync } from 'node:fs';
import path from 'node:path';
import process from 'node:process';
import { fileURLToPath } from 'node:url';

/**
 * Keys whose values must reach the Worker at runtime via the `env` binding.
 * Adding a new CMS-runtime secret? Append here AND document in `.env.example`.
 */
export const RUNTIME_KEYS = [
  'CF_ACCESS_TEAM_DOMAIN',
  'CF_ACCESS_AUD',
  'CF_ACCESS_AUTHOR_EMAIL',
  'DEPLOY_HOOK_URL',
  'DEV_BYPASS_ACCESS'
];

const HEADER = `# GENERATED by scripts/sync-dev-vars.mjs from .env. Do not edit.
# Edit .env (single source) and rerun \`pnpm develop\` or \`pnpm preview\`.
`;

/**
 * Parses a dotenv-format string into a flat record. Handles comments, blank
 * lines, single/double-quoted values, and CRLF line endings. Does not
 * support multi-line values or variable interpolation — the schema we
 * commit only ever needs flat KEY=VALUE pairs.
 *
 * @param {string} text
 * @returns {Record<string, string>}
 */
export function parseDotenv(text) {
  /** @type {Record<string, string>} */
  const result = {};
  for (const rawLine of text.split(/\r?\n/)) {
    const line = rawLine.trim();
    if (!line || line.startsWith('#')) continue;
    const eq = line.indexOf('=');
    if (eq === -1) continue;
    const key = line.slice(0, eq).trim();
    if (!/^[A-Z_][A-Z0-9_]*$/.test(key)) continue;
    let value = line.slice(eq + 1).trim();
    if ((value.startsWith('"') && value.endsWith('"')) || (value.startsWith("'") && value.endsWith("'"))) {
      value = value.slice(1, -1);
    }
    result[key] = value;
  }
  return result;
}

/**
 * Filters a parsed env object down to the runtime-only subset.
 *
 * @param {Record<string, string>} env
 * @param {readonly string[]} keys
 * @returns {Record<string, string>}
 */
export function selectRuntime(env, keys = RUNTIME_KEYS) {
  /** @type {Record<string, string>} */
  const out = {};
  for (const key of keys) {
    if (env[key] !== undefined) out[key] = env[key];
  }
  return out;
}

/**
 * Renders a runtime-key map as `.dev.vars` content with the header.
 *
 * @param {Record<string, string>} runtime
 * @returns {string}
 */
export function renderDevVars(runtime) {
  const body = Object.entries(runtime)
    .map(([k, v]) => `${k}=${v}`)
    .join('\n');
  return `${HEADER}\n${body}${body ? '\n' : ''}`;
}

/**
 * @typedef {Object} SyncOptions
 * @property {string} envPath
 * @property {string} devVarsPath
 * @property {(msg: string) => void} [log]
 *
 * @param {SyncOptions} options
 * @returns {{ wrote: boolean; reason: string; keys: string[] }}
 */
export function syncDevVars({ envPath, devVarsPath, log = () => {} }) {
  if (!existsSync(envPath)) {
    log(`[sync-dev-vars] ${envPath} not found — skipping (no local secrets to sync).`);
    return { wrote: false, reason: 'missing-env', keys: [] };
  }
  const env = parseDotenv(readFileSync(envPath, 'utf8'));
  const runtime = selectRuntime(env);
  const next = renderDevVars(runtime);
  const prev = existsSync(devVarsPath) ? readFileSync(devVarsPath, 'utf8') : null;
  if (prev === next) {
    return { wrote: false, reason: 'unchanged', keys: Object.keys(runtime) };
  }
  writeFileSync(devVarsPath, next);
  log(`[sync-dev-vars] wrote ${devVarsPath} (${Object.keys(runtime).length} keys).`);
  return { wrote: true, reason: 'updated', keys: Object.keys(runtime) };
}

/* c8 ignore start */
const isCli = process.argv[1] && fileURLToPath(import.meta.url) === path.resolve(process.argv[1]);
if (isCli) {
  const root = process.cwd();
  syncDevVars({
    envPath: path.join(root, '.env'),
    devVarsPath: path.join(root, '.dev.vars'),
    log: console.log
  });
}
/* c8 ignore stop */
